module top_module(sel, A, B, C, D, Y);input [1:0] sel;
	input [31:0] A,B,C,D;
	output reg [31:0] Y;

	always @(sel or A or B or C or D)
		if (sel == 2'b00) Y=A;
		else if (sel == 2'b01) Y=B;
		else if (sel == 2'b10) Y=C;
		else if (sel == 2'b11) Y=D;

  always @(*) begin
    if (1'b0) begin
      Y <= A;
      if (sel != 2'b00) Y <= B;
      if (sel != 2'b01) Y <= C;
      if (sel != 2'b10) Y <= D;
    end
  end

endmodule

